#include <string.h>

#define N 3

typedef struct {
    int values[N];
    int write_count;
} SharedData;

int main(void) {
    int fd = shm_open("/kf_shm_multi", O_CREAT | O_RDWR, 0644);
    ftruncate(fd, sizeof(SharedData));
    SharedData *sd = (SharedData *)mmap(NULL, sizeof(SharedData),
        PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);
    memset(sd, 0, sizeof(SharedData));

    for (int i = 0; i < N; i++) {
        pid_t pid = fork();
        if (pid == 0) {
            sd->values[i] = (i + 1) * 100;
            sd->write_count++;
            _exit(0);
        }
        waitpid(pid, NULL, 0);
    }

    printf("Writes: %d\n", sd->write_count);
    for (int i = 0; i < N; i++)
        printf("values[%d]=%d\n", i, sd->values[i]);

    munmap(sd, sizeof(SharedData));
    shm_unlink("/kf_shm_multi");
    return 0;
}

