/* == EXEMPLE =======================================
 * 2 ecrivains sequentiels en shm
 * ================================================= */
void example_multi(void) {
    int fd = shm_open("/kf_ex_multi", O_CREAT|O_RDWR, 0644);
    ftruncate(fd, 2*sizeof(int)+sizeof(int));
    int *vals = (int *)mmap(NULL, 3*sizeof(int), PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd); memset(vals, 0, 3*sizeof(int));
    for (int i = 0; i < 2; i++) {
        pid_t p = fork();
        if (p == 0) { vals[i] = (i+1)*50; vals[2]++; _exit(0); }
        waitpid(p, NULL, 0);
    }
    printf("[%d,%d] w=%d\n", vals[0], vals[1], vals[2]);
    munmap(vals, 3*sizeof(int)); shm_unlink("/kf_ex_multi");
}
/* Resultat: [50,100] w=2 */

